    /** @type {number} Hue offset for color cycling. */
    this.hueOffset = 0;
    /** @type {number} Last hue shift marker. */
    this._lastHueShift = 0;

    // ──── Audio mode ────
    /** @type {string} Current audio mode ('mp3', 'midi', 'synth'). */
    this.mode = AUDIO_MODE.MP3;

    // ──── MIDI mode references ────
